"use strict";(globalThis.webpackChunktjm_solutions_site=globalThis.webpackChunktjm_solutions_site||[]).push([[4375],{5445(e){e.exports=JSON.parse('{"permalink":"/articles/2026/01/18/pure-functions","source":"@site/blog/2026-01-18-pure-functions.mdx","title":"Pure Functions: Your First Step Toward Bug-Free Concurrency","description":"How pure functions \u2014 same inputs, same outputs, no side effects \u2014 eliminate entire categories of concurrency bugs and make pricing, eligibility, and promotion logic reliably testable at scale.","date":"2026-01-18T00:00:00.000Z","tags":[{"inline":true,"label":"functional-programming","permalink":"/articles/tags/functional-programming"},{"inline":true,"label":"architecture","permalink":"/articles/tags/architecture"},{"inline":true,"label":"blog","permalink":"/articles/tags/blog"},{"inline":true,"label":"concurrency","permalink":"/articles/tags/concurrency"}],"readingTime":7.59,"hasTruncateMarker":true,"authors":[{"name":"Tony Moores","title":"Founder & Principal Consultant, TJM Solutions","url":"https://www.tjm.solutions/about","socials":{"linkedin":"https://www.linkedin.com/in/tony-moores/"},"imageURL":"/img/tjm-solutions-logo.png","key":"tony","page":null}],"frontMatter":{"title":"Pure Functions: Your First Step Toward Bug-Free Concurrency","description":"How pure functions \u2014 same inputs, same outputs, no side effects \u2014 eliminate entire categories of concurrency bugs and make pricing, eligibility, and promotion logic reliably testable at scale.","date":"2026-01-18T00:00:00.000Z","authors":["tony"],"tags":["functional-programming","architecture","blog","concurrency"],"image":"/img/funcprog-1.jpg","series":"Functional Programming Isn\'t Just for Academics","series_part":3},"unlisted":false,"prevItem":{"title":"Thinking in Expressions, Not Statements","permalink":"/articles/2026/01/25/thinking-in-expressions-not-statements"},"nextItem":{"title":"Immutability by Default: The Foundation of Reliable Systems","permalink":"/articles/2026/01/11/immutability-by-default"}}')},7960(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>o,default:()=>u,frontMatter:()=>r,metadata:()=>i,toc:()=>l});var i=n(5445),a=n(4848),s=n(8453);const r={title:"Pure Functions: Your First Step Toward Bug-Free Concurrency",description:"How pure functions \u2014 same inputs, same outputs, no side effects \u2014 eliminate entire categories of concurrency bugs and make pricing, eligibility, and promotion logic reliably testable at scale.",date:new Date("2026-01-18T00:00:00.000Z"),authors:["tony"],tags:["functional-programming","architecture","blog","concurrency"],image:"/img/funcprog-1.jpg",series:"Functional Programming Isn't Just for Academics",series_part:3},o=void 0,c={authorsImageUrls:[void 0]},l=[{value:"When a Pricing Function Isn&#39;t Really a Function",id:"when-a-pricing-function-isnt-really-a-function",level:2},{value:"Repricing as a Pure Function",id:"repricing-as-a-pure-function",level:2},{value:"Referential Transparency: Why Purity Matters Beyond &quot;Clean Code&quot;",id:"referential-transparency-why-purity-matters-beyond-clean-code",level:2},{value:"Purity and Edge Caching: Why Predictability Scales",id:"purity-and-edge-caching-why-predictability-scales",level:2},{value:"Why Java Makes This a Struggle",id:"why-java-makes-this-a-struggle",level:2},{value:"Why Scala Makes Purity Natural",id:"why-scala-makes-purity-natural",level:2},{value:"The Architectural Insight",id:"the-architectural-insight",level:2}];function h(e){const t={code:"code",em:"em",h2:"h2",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,s.R)(),...e.components},{Head:n}=t;return n||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Head",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n,{children:(0,a.jsx)("link",{rel:"canonical",href:"https://tmoores.medium.com/pure-functions-your-first-step-toward-bug-free-concurrency-d3db82d07b66"})}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.em,{children:"Functional Programming Isn't Just for Academics \u2014 Part 3"})}),"\n",(0,a.jsxs)(t.p,{children:["In Part 2, we explored how mutable state \u2014 especially state that someone once believed was a fact \u2014 tends to drift over time, and how this drift destabilizes large systems. Immutability is a corrective measure: if something is a fact, preserve it. But immutability addresses only one dimension of stability. The ",(0,a.jsx)(t.em,{children:"other"})," dimension concerns the way behavior is expressed \u2014 whether the logic we rely on actually does what its name claims, or whether it also does several other things we never quite account for."]}),"\n",(0,a.jsx)(t.p,{children:"When developers talk about pure functions, they often recite the textbook definition: same inputs, same outputs, no side effects. It's correct, but it undersells the point. Purity is not an aesthetic choice or an academic curiosity. It is a way of reclaiming control over the semantics of your system. It is how you establish that a piece of business logic actually behaves like business logic, rather than a negotiation with global state, shared caches, volatile time checks, and whichever service instance happens to answer the call."}),"\n",(0,a.jsx)(t.p,{children:"Commerce systems surface this problem bluntly. Consider cart repricing. A cart is a negotiation. Shoppers add and remove items, the system reevaluates promotions, seasonal rules apply or expire, and flash sales may activate in the middle of a session. A change to the cart or its context prompts a recalculation. The mechanics sound straightforward; the reality rarely is. Many pricing engines embed side effects throughout their logic: they reach into global registries of promotions, pull loyalty tiers from shared caches, write audit logs during discount evaluation, and update counters in observability systems. None of these are wrong in isolation, but collectively they entangle pricing with the world around it and make the outcome nondeterministic under concurrency."}),"\n",(0,a.jsx)(t.p,{children:"Everyone who has worked in this space has seen a cart fluctuate unpredictably: a discount that appears on one request and disappears on the next; a price that depends on which node in the cluster answered; totals that drift because two threads read promotions at different moments. Even the order in which items are carted may cause discrepancies. The arithmetic is simple; the impurities are not."}),"\n",(0,a.jsx)(t.h2,{id:"when-a-pricing-function-isnt-really-a-function",children:"When a Pricing Function Isn't Really a Function"}),"\n",(0,a.jsx)(t.p,{children:"A simplified but representative Java-style example might look like this:"}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{className:"language-java",children:'public Money reprice(Cart cart) {\n    // Reads global promotion rules (mutable, time-sensitive)\n    List<Promotion> activePromos = PromotionRegistry.getActivePromotions();\n    // Writes to an audit log as a side effect\n    PromoAudit.log("Repricing cart " + cart.getId());\n    // Touches a shared counter (concurrency hazard)\n    Metrics.cartRepriced.increment();\n    // Checks for a time-based flash sale\n    boolean flashSale = FlashSale.isActive();\n    Money total = Money.zero();\n    for (CartItem item : cart.getItems()) {\n        Money price = item.getListPrice();\n        for (Promotion p : activePromos) {\n            price = p.apply(price, item, flashSale);\n        }\n        total = total.plus(price.multiply(item.getQuantity()));\n    }\n    return total;\n}\n'})}),"\n",(0,a.jsx)(t.p,{children:"Nothing here looks outrageous, yet almost every line compromises determinism. The function's behavior depends on global mutable state, external side effects, the system clock, and the order in which items and promotions happened to be loaded or refreshed. Under concurrency, these dependencies do not stay stable. A thread that begins computing while a flash-sale toggle is flipping or while promotions are updating may produce a different price from a thread that begins a millisecond later."}),"\n",(0,a.jsx)(t.p,{children:"This function pretends to compute a price, but it actually conducts a conversation with the universe."}),"\n",(0,a.jsx)(t.p,{children:"Testing becomes fragile, because the function has more external dependencies than explicit parameters. Reproducibility becomes elusive. Parallel execution becomes unsafe. And when prices shift unexpectedly, engineers struggle to pinpoint the cause because the logic is entangled with operational concerns."}),"\n",(0,a.jsx)(t.h2,{id:"repricing-as-a-pure-function",children:"Repricing as a Pure Function"}),"\n",(0,a.jsx)(t.p,{children:"A pure formulation makes all dependencies explicit:"}),"\n",(0,a.jsx)(t.pre,{children:(0,a.jsx)(t.code,{className:"language-scala",children:"final case class PricingContext(\n  promotions: List[PromotionRule],\n  flashSaleActive: Boolean\n)\n\ndef reprice(cart: Cart, ctx: PricingContext): Money = {\n  cart.items.foldLeft(Money.zero) { (total, item) =>\n    val base = item.listPrice\n    val discounted = ctx.promotions.foldLeft(base) { (price, rule) =>\n      rule.apply(price, item, ctx.flashSaleActive)\n    }\n    total + (discounted * item.quantity)\n  }\n}\n"})}),"\n",(0,a.jsx)(t.p,{children:"Here the repricing logic depends only on the cart and a supplied pricing context. There are no global reads, no shared state updates, no logging, no timers. The logic performs one job: calculate a price."}),"\n",(0,a.jsx)(t.p,{children:"This version is trivial to test: provide a cart, provide a context, expect a result. It is trivial to reason about because everything influencing the outcome is visible in the function's signature. It is safe in the presence of concurrency, because nothing inside the function can be interfered with by other threads. And it is reproducible: the same inputs always yield the same outputs."}),"\n",(0,a.jsx)(t.p,{children:"Purity does not remove complexity; it places it in the open, where it can be understood, controlled, and scaled."}),"\n",(0,a.jsx)(t.h2,{id:"referential-transparency-why-purity-matters-beyond-clean-code",children:'Referential Transparency: Why Purity Matters Beyond "Clean Code"'}),"\n",(0,a.jsx)(t.p,{children:"When a function is pure, we gain referential transparency \u2014 the ability to replace a function call with its result without altering program behavior. This sounds theoretical, but it is the property that makes reasoning compositional. When referential transparency holds, you do not need to know when or where a function was called, or which node handled the request; you only need the inputs. This dramatically simplifies:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"retry logic"}),", because repeating a pure computation cannot cause harm"]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"parallel and distributed execution"}),", because the evaluation order does not matter"]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"caching and memoization"}),", because the output is stable and keyed only by explicit inputs"]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"testing"}),", because there is no environment to simulate"]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"debugging"}),", because the function either returns the correct value or it does not \u2014 there is nothing hidden around it"]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"In commerce, where price, discount, and eligibility computations run millions of times per hour, these properties translate directly into reliability and cost efficiency."}),"\n",(0,a.jsx)(t.h2,{id:"purity-and-edge-caching-why-predictability-scales",children:"Purity and Edge Caching: Why Predictability Scales"}),"\n",(0,a.jsx)(t.p,{children:"Digital commerce is dynamic by nature. Promotions change because marketing wants them to. Loyalty tiers change because customers earn or lose status. Inventory and assortment shift by the minute. Flash sales activate for short windows. Every one of these changes challenges a system's ability to cache results at the edge, where speed matters most."}),"\n",(0,a.jsx)(t.p,{children:"Teams typically rely on heuristics: cache for a few minutes, or a few seconds, or not at all. They do this because they cannot be certain when cached results are still valid. The pricing function depends implicitly on global state, and those dependencies are not visible in the function's signature. Without a clear dependency model, cache invalidation becomes guesswork."}),"\n",(0,a.jsx)(t.p,{children:"Pure functions solve this elegantly. When your pricing logic's dependencies are explicit \u2014 promotions, flash-sale switches, loyalty attributes, timestamps \u2014 each of those inputs becomes part of the cache key. If none have changed, the cached price is correct. If one has changed, the cache must be bypassed or refreshed. There is no guesswork, because the shape of the function defines the shape of the invalidation strategy."}),"\n",(0,a.jsx)(t.p,{children:"Edge caching becomes a mechanical extension of the domain model rather than a probabilistic optimization. Akamai, Cloudflare, Fastly, and others become almost embarrassingly effective when the application provides a deterministic calculation. And because pure repricing functions are safe to run on any node, the edge can shoulder far more work without compromising correctness."}),"\n",(0,a.jsx)(t.p,{children:"Purity does not eliminate dynamism; it allows the system to respond to it predictably."}),"\n",(0,a.jsx)(t.h2,{id:"why-java-makes-this-a-struggle",children:"Why Java Makes This a Struggle"}),"\n",(0,a.jsx)(t.p,{children:"Java developers can write pure functions, but the language and its surrounding ecosystem do not encourage it. Frameworks default to global configuration, dependency injection boundaries blur the distinction between construction and execution, and most libraries assume mutability. The language does not prevent accidental side effects or hidden dependencies; it leaves the burden of discipline on developers and reviewers."}),"\n",(0,a.jsx)(t.p,{children:"In small teams, that discipline holds. In organizations with dozens of contributors, it frays. Concurrency and testing magnify the cost of those fractures."}),"\n",(0,a.jsx)(t.h2,{id:"why-scala-makes-purity-natural",children:"Why Scala Makes Purity Natural"}),"\n",(0,a.jsx)(t.p,{children:"Scala makes pure functions the intuitive choice. Immutable data structures are the default; methods tend to be referentially transparent unless you explicitly introduce side effects; function composition is expressive; and domain models are concise enough that purity does not require elaborate scaffolding. The language exposes, rather than conceals, a function's dependencies. And because of that, concurrency comes almost for free."}),"\n",(0,a.jsx)(t.p,{children:"The distinction is not that Scala prevents impurity. It is that Scala makes purity the simplest way to express your domain's logic. The cleaner the logic, the cleaner the concurrency story around it."}),"\n",(0,a.jsx)(t.h2,{id:"the-architectural-insight",children:"The Architectural Insight"}),"\n",(0,a.jsx)(t.p,{children:"Pure functions do not solve every problem. But they solve the class of problems that make pricing, promotions, and eligibility logic unpredictable under load. They enable caching strategies that are rational rather than heuristic. They make concurrency manageable without locks. They remove whole categories of bugs rather than patching them reactively. And when combined with immutable data, they create systems whose behavior is a function of their inputs \u2014 not an artifact of their circumstances."}),"\n",(0,a.jsx)(t.p,{children:"Purity is how you take the drift out of behavior. It is how you make logic portable, testable, and naturally scalable. And it is how you prepare a system to operate confidently at the edge as well as at the core."}),"\n",(0,a.jsx)(t.p,{children:"This is the foundation for the next part of the series, where we will look more closely at how shifting from statement-based to expression-based thinking eliminates hidden state and cognitive overhead in system design."})]})}function u(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(h,{...e})}):h(e)}},8453(e,t,n){n.d(t,{R:()=>r,x:()=>o});var i=n(6540);const a={},s=i.createContext(a);function r(e){const t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);